import React, { Component } from "react";
import $ from "jquery";
import "./App.scss";
import Header from "./components/Header";
import Footer from "./components/Footer";
import About from "./components/About";
import Experience from "./components/Experience";
import Projects from "./components/Projects";
import Skills from "./components/Skills";
import { motion } from "framer-motion";

class App extends Component {
  constructor(props) {
    super();
    this.state = {
      foo: "bar",
      resumeData: {},
      sharedData: {},
      // Initialize with the global primary language
      activeLanguage: window.$primaryLanguage 
    };
  }

  applyPickedLanguage(pickedLanguage, oppositeLangIconId) {
    // 1. Update React state for animations
    this.setState({ activeLanguage: pickedLanguage });

    // 2. Original brightness logic
    this.swapCurrentlyActiveLanguage(oppositeLangIconId);

    // 3. Update document and load JSON
    document.documentElement.lang = pickedLanguage;
    var resumePath =
      document.documentElement.lang === window.$primaryLanguage
        ? `res_primaryLanguage.json`
        : `res_secondaryLanguage.json`;
    this.loadResumeFromPath(resumePath);
  }

  swapCurrentlyActiveLanguage(oppositeLangIconId) {
    var pickedLangIconId =
      oppositeLangIconId === window.$primaryLanguageIconId
        ? window.$secondaryLanguageIconId
        : window.$primaryLanguageIconId;

    const oppositeElem = document.getElementById(oppositeLangIconId);
    const pickedElem = document.getElementById(pickedLangIconId);

    if (oppositeElem) oppositeElem.removeAttribute("filter");
    if (pickedElem) pickedElem.setAttribute("filter", "brightness(40%)");
  }

  componentDidMount() {
    this.loadSharedData();
    // Ensure the initial language is applied correctly
    this.applyPickedLanguage(
      window.$primaryLanguage,
      window.$secondaryLanguageIconId
    );
  }

  loadResumeFromPath(path) {
    $.ajax({
      url: path,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ resumeData: data });
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error loading resume:", err);
      },
    });
  }

  loadSharedData() {
    $.ajax({
      url: `portfolio_shared_data.json`,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ sharedData: data });
        document.title = data.basic_info.name;
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error loading shared data:", err);
      },
    });
  }

render() {
    return (
      <div>
        <Header sharedData={this.state.sharedData.basic_info} />

        <div className="col-md-12 mx-auto text-center language" style={{ padding: "30px 0" }}>

          {/* UK Flag Container */}
          <motion.div
            onClick={() =>
              this.applyPickedLanguage(
                window.$primaryLanguage,
                window.$secondaryLanguageIconId
              )
            }
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px"
            }}
            whileHover={{ scale: 1.15 }}
            whileTap={{ scale: 0.95 }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-united-kingdom"
              data-inline="false"
              id={window.$primaryLanguageIconId}
              style={{ 
                fontSize: "45px",
                transition: "all 0.4s ease",
                // If this is active, full brightness. If not, dim it.
                filter: this.state.activeLanguage === window.$primaryLanguage 
                  ? "brightness(100%)" 
                  : "brightness(50%) grayscale(30%)",
                opacity: this.state.activeLanguage === window.$primaryLanguage ? 1 : 0.6
              }}
            ></span>
          </motion.div>

          {/* India Flag Container */}
          <motion.div
            onClick={() =>
              this.applyPickedLanguage(
                window.$secondaryLanguage,
                window.$primaryLanguageIconId
              )
            }
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px"
            }}
            whileHover={{ scale: 1.15 }}
            whileTap={{ scale: 0.95 }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-india"
              data-inline="false"
              id={window.$secondaryLanguageIconId}
              style={{ 
                fontSize: "45px",
                transition: "all 0.4s ease",
                // If this is active, full brightness. If not, dim it.
                filter: this.state.activeLanguage === window.$secondaryLanguage 
                  ? "brightness(100%)" 
                  : "brightness(50%) grayscale(30%)",
                opacity: this.state.activeLanguage === window.$secondaryLanguage ? 1 : 0.6
              }}
            ></span>
          </motion.div>
        </div>

        <About
          resumeBasicInfo={this.state.resumeData.basic_info}
          sharedBasicInfo={this.state.sharedData.basic_info}
        />
        <Projects
          resumeProjects={this.state.resumeData.projects}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Skills
          sharedSkills={this.state.sharedData.skills}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Experience
          resumeExperience={this.state.resumeData.experience}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Footer sharedBasicInfo={this.state.sharedData.basic_info} />
      </div>
    );
  }
}

export default App;
